const data = $input.first().json.body.data;

return [{
  json: {
    email: data.customer.email,
    firstName: data.customer.firstName || '',
    lastName: data.customer.lastName || '',
    productName: data.product.name,
    amount: data.order.amount / 100,
    currency: data.order.currency.toUpperCase(),
    sessionId: data.order.sessionId,
    paymentIntentId: data.order.paymentIntentId,
    needsInvoice: data.invoice?.needsInvoice || false,
    invoiceNip: data.invoice?.nip || null,
    invoiceCompany: data.invoice?.companyName || null,
    invoiceAddress: data.invoice?.address || null,
    invoiceCity: data.invoice?.city || null,
    invoicePostalCode: data.invoice?.postalCode || null,
    invoiceCountry: data.invoice?.country || 'PL'
  }
}];

const d = $input.first().json;
const today = new Date().toISOString().split('T')[0];

// Payment date = today (invoice issued day of purchase)
const paymentDate = today;

// VAT rate — change here if your products use a different rate
const vatRate = '23%';

// Net price = gross amount / (1 + VAT)
const vatMultiplier = vatRate === '23%' ? 1.23
  : vatRate === '8%' ? 1.08
  : vatRate === '5%' ? 1.05
  : vatRate === '0%' ? 1.00
  : 1.00; // 'zw' treated as gross = net
const netPrice = vatRate === 'zw'
  ? d.amount
  : Math.round((d.amount / vatMultiplier) * 100) / 100;

const buyerName = d.invoiceCompany || `${d.firstName} ${d.lastName}`.trim() || d.email;

return [{
  json: {
    payload: {
      invoices: {
        invoice: {
          paymentmethod: 'transfer',
          paymentdate: paymentDate,
          type: 'normal',
          status: 'paid',
          alreadypaid: d.amount,
          currency: d.currency || 'PLN',
          buyer: {
            name: buyerName,
            nip: d.invoiceNip,
            street: d.invoiceAddress || '',
            zip: d.invoicePostalCode || '',
            city: d.invoiceCity || '',
            country: d.invoiceCountry || 'PL',
            email: d.email
          },
          invoicecontents: {
            invoicecontent: [
              {
                name: d.productName,
                unit: 'szt.',
                count: 1,
                price: netPrice,
                vat_rate: vatRate
              }
            ]
          }
        }
      }
    },
    _meta: {
      sessionId: d.sessionId,
      paymentIntentId: d.paymentIntentId,
      buyerEmail: d.email
    }
  }
}];
